import{_ as i,o as a,c as l,ag as s}from"./chunks/framework.BZohXCq9.js";const o="/bima/web-page-light.svg",e="/bima/web-page-dark.svg",n="/bima/shopping-light.svg",r="/bima/shopping-dark.svg",c="/bima/mail-light.svg",h="/bima/mail-dark.svg",d="/bima/wechat-light.svg",g="/bima/wechat-dark.svg",f=JSON.parse('{"title":"关于必码","description":"","frontmatter":{},"headers":[{"level":1,"title":"关于必码","slug":"关于必码","link":"#关于必码","children":[{"level":2,"title":"我们的理念","slug":"我们的理念","link":"#我们的理念","children":[]},{"level":2,"title":"业务服务","slug":"业务服务","link":"#业务服务","children":[{"level":3,"title":"CAS 认证服务","slug":"cas-认证服务","link":"#cas-认证服务","children":[]},{"level":3,"title":"开源项目定制","slug":"开源项目定制","link":"#开源项目定制","children":[]},{"level":3,"title":"技术咨询服务","slug":"技术咨询服务","link":"#技术咨询服务","children":[]}]},{"level":2,"title":"联系我们","slug":"联系我们","link":"#联系我们","children":[]}]}],"relativePath":"bima/about.md","filePath":"bima/about.md"}'),p={name:"bima/about.md"};function m(u,t,b,v,_,k){return a(),l("div",null,[...t[0]||(t[0]=[s('<h1 id="关于必码" tabindex="-1">关于必码 <a class="header-anchor" href="#关于必码" aria-label="Permalink to &quot;关于必码&quot;">​</a></h1><p>北京必码科技工作室（简称：必码），专注于开源项目定制开发与技术服务。我们秉承&quot;只写必要的代码&quot;的核心理念，致力于为客户提供轻量化、贴合业务需求的技术解决方案，让开源技术真正为业务创造价值。</p><h2 id="我们的理念" tabindex="-1">我们的理念 <a class="header-anchor" href="#我们的理念" aria-label="Permalink to &quot;我们的理念&quot;">​</a></h2><p>必码坚持&quot;小而精、专而深&quot;的服务原则，聚焦开源生态，专注技术落地。我们深知企业在使用开源产品时面临的&quot;适配难、定制难&quot;痛点，凭借丰富的开源开发经验，从需求分析到交付运维，全程细致跟进，力求让客户以最小的成本解决最实际的问题。</p><h2 id="业务服务" tabindex="-1">业务服务 <a class="header-anchor" href="#业务服务" aria-label="Permalink to &quot;业务服务&quot;">​</a></h2><h3 id="cas-认证服务" tabindex="-1">CAS 认证服务 <a class="header-anchor" href="#cas-认证服务" aria-label="Permalink to &quot;CAS 认证服务&quot;">​</a></h3><p>基于耶鲁大学开源的 CAS（中央认证服务）项目，提供轻量化定制开发，解决企业多系统单点登录问题，支持 LDAP、OAuth、SAML 等多种认证协议，实现与现有业务系统的无缝集成。</p><blockquote><ul><li><strong>轻量化定制</strong>：只做必要开发，避免功能冗余</li><li><strong>安全可靠</strong>：支持多种认证方式和协议</li><li><strong>无缝集成</strong>：与现有业务系统完美对接</li><li><strong>持续支持</strong>：提供项目交付后的技术支持</li></ul></blockquote><h3 id="开源项目定制" tabindex="-1">开源项目定制 <a class="header-anchor" href="#开源项目定制" aria-label="Permalink to &quot;开源项目定制&quot;">​</a></h3><p>基于主流开源项目进行深度定制，包括但不限于身份认证、权限管理、微服务治理等领域，满足企业特定业务场景的个性化需求。</p><blockquote><ul><li><strong>需求驱动</strong>：深入理解客户业务场景</li><li><strong>技术选型</strong>：选用最适合的技术方案</li><li><strong>敏捷开发</strong>：基于成熟框架快速实现</li><li><strong>性能优化</strong>：确保系统高效稳定运行</li></ul></blockquote><h3 id="技术咨询服务" tabindex="-1">技术咨询服务 <a class="header-anchor" href="#技术咨询服务" aria-label="Permalink to &quot;技术咨询服务&quot;">​</a></h3><p>提供专业的开源技术咨询服务，帮助企业制定合理的技术路线，解决技术难题，提升系统架构的可靠性和可扩展性。</p><blockquote><ul><li><strong>架构设计</strong>：提供系统架构优化建议</li><li><strong>技术指导</strong>：分享开源项目最佳实践</li><li><strong>安全评估</strong>：识别和解决潜在安全风险</li><li><strong>性能调优</strong>：提升系统性能和用户体验</li></ul></blockquote><h2 id="联系我们" tabindex="-1">联系我们 <a class="header-anchor" href="#联系我们" aria-label="Permalink to &quot;联系我们&quot;">​</a></h2><p>必码科技期待与您合作，以技术为桥，共创价值！</p><div class="contact-info"><div class="contact-item"><img src="'+o+'" class="vp-light-only" width="24" height="24"><img src="'+e+'" class="vp-dark-only" width="24" height="24"><span>官方网址：https://bima.cc</span></div></div><div class="contact-info"><div class="contact-item"><img src="'+n+'" class="vp-light-only" width="24" height="24"><img src="'+r+'" class="vp-dark-only" width="24" height="24"><span>官方店铺：https://bima.taobao.com</span></div></div><div class="contact-info"><div class="contact-item"><img src="'+c+'" class="vp-light-only" width="24" height="24"><img src="'+h+'" class="vp-dark-only" width="24" height="24"><span>联系邮箱：bima.cc@qq.com</span></div></div><div class="contact-info"><div class="contact-item"><img src="'+d+'" class="vp-light-only" width="24" height="24"><img src="'+g+'" class="vp-dark-only" width="24" height="24"><span>联系微信：e18929958</span></div></div>',20)])])}const w=i(p,[["render",m]]);export{f as __pageData,w as default};
